import Foundation

let questions4: [QuizQuestion] = [
QuizQuestion(id:231,question:"Qual é o primeiro livro do Novo Testamento?",options:["Marcos","Lucas","Mateus","João"],correctIndex:2,explanation:"Mateus é o primeiro livro do NT, escrito para judeus demonstrando que Jesus é o Messias prometido.",reference:"Mateus 1:1",category:.geral,propheticMeaning:"Mateus abre com a genealogia de Jesus como filho de Davi e Abraão, conectando-o às duas alianças fundamentais do AT."),
QuizQuestion(id:232,question:"Qual é o livro mais longo da Bíblia?",options:["Gênesis","Jeremias","Salmos","Isaías"],correctIndex:2,explanation:"O livro de Salmos é o mais longo com 150 capítulos, sendo uma coleção de hinos, lamentos e orações.",reference:"Salmos 1-150",category:.geral,propheticMeaning:"Muitos Salmos são diretamente messiânicos (Sl 2, 22, 110), profetizando detalhes da vida, morte e reinado de Cristo."),
QuizQuestion(id:233,question:"Qual é o versículo mais curto da Bíblia?",options:["'Deus é amor'","'Jesus chorou'","'Orai sempre'","'Crede em Deus'"],correctIndex:1,explanation:"'Jesus chorou' (João 11:35) mostra a humanidade de Cristo diante do túmulo de Lázaro.",reference:"João 11:35",category:.geral,propheticMeaning:"Jesus chorando revela que nosso Sumo Sacerdote se comove com nossas fraquezas (Hb 4:15) — ele é plenamente humano e divino."),
QuizQuestion(id:234,question:"Qual apóstolo escreveu mais livros do Novo Testamento?",options:["Pedro","João","Paulo","Mateus"],correctIndex:2,explanation:"Paulo escreveu 13 ou 14 epístolas do NT, de Romanos a Filemom.",reference:"Romanos 1:1",category:.geral,propheticMeaning:"Paulo, ex-perseguidor da Igreja, tornando-se seu maior teólogo prova que a graça transforma até o maior dos pecadores (1 Tm 1:15-16)."),
QuizQuestion(id:235,question:"Quantos livros tem a Bíblia protestante?",options:["60","66","72","73"],correctIndex:1,explanation:"A Bíblia tem 66 livros: 39 no AT e 27 no NT.",reference:"Gênesis a Apocalipse",category:.geral,propheticMeaning:"A unidade dos 66 livros por mais de 40 autores em 1.500 anos aponta para a inspiração do único Espírito Santo por trás de toda a Escritura."),
QuizQuestion(id:236,question:"Qual é o último livro da Bíblia?",options:["Judas","Hebreus","Apocalipse","3 João"],correctIndex:2,explanation:"Apocalipse é o último livro, escrito pelo apóstolo João em Patmos, revelando o fim dos tempos.",reference:"Apocalipse 1:1",category:.geral,propheticMeaning:"Apocalipse fecha o círculo de Gênesis: o jardim perdido (Gn 3) é restaurado na cidade nova (Ap 22)."),
QuizQuestion(id:237,question:"Qual é o tema central de toda a Bíblia?",options:["A história do povo judeu","A redenção da humanidade por Cristo","As leis morais","A criação do universo"],correctIndex:1,explanation:"O tema central é a redenção da humanidade por Jesus Cristo — do Gênesis ao Apocalipse.",reference:"Lucas 24:27; João 5:39",category:.geral,propheticMeaning:"Jesus disse: 'Em todas as Escrituras as coisas que a ele se referiam' (Lc 24:27) — Cristo é o centro de toda revelação bíblica."),
QuizQuestion(id:238,question:"Qual foi o idioma original do Novo Testamento?",options:["Latim","Hebraico","Aramaico","Grego"],correctIndex:3,explanation:"O NT foi escrito em grego koiné — o idioma comum do mundo mediterrâneo no primeiro século.",reference:"2 Timóteo 3:16",category:.geral,propheticMeaning:"Deus escolheu o grego koiné, língua franca do mundo, para registrar o NT — o evangelho é para 'todas as nações' (Mt 28:19)."),
QuizQuestion(id:239,question:"Qual é o significado do nome 'Jesus'?",options:["Filho de Deus","O Senhor salva","Luz do mundo","Rei de Israel"],correctIndex:1,explanation:"Jesus (Yeshua) significa 'O Senhor salva'. O anjo disse: 'Chamarás seu nome Jesus, porque ele salvará o seu povo.'",reference:"Mateus 1:21",category:.geral,propheticMeaning:"O próprio nome de Jesus proclama sua missão: 'O Filho do Homem veio buscar e salvar o perdido' (Lc 19:10)."),
QuizQuestion(id:240,question:"O que significa 'Cristo'?",options:["Salvador","Ungido/Messias","Senhor","Filho de Davi"],correctIndex:1,explanation:"Cristo (grego) e Messias (hebraico) significam 'O Ungido' — reis, sacerdotes e profetas eram ungidos.",reference:"João 1:41",category:.geral,propheticMeaning:"Jesus cumpre os três ofícios do ungido: Profeta (Dt 18:18), Sacerdote (Sl 110:4) e Rei (2 Sm 7:13)."),
QuizQuestion(id:241,question:"O que significa 'evangelho'?",options:["Livro sagrado","Boa notícia","Lei de Deus","Palavra de Deus"],correctIndex:1,explanation:"Evangelho (euangelion) significa 'boa notícia' — que Jesus morreu pelos nossos pecados e ressuscitou.",reference:"1 Coríntios 15:1-4",category:.geral,propheticMeaning:"As boas novas de que o pecado foi vencido satisfazem a mais profunda necessidade humana: reconciliação com Deus, prometida desde Gênesis 3:15."),
QuizQuestion(id:242,question:"Qual era a profissão de Paulo antes de ser apóstolo?",options:["Pescador","Carpinteiro","Fariseu e perseguidor da Igreja","Cobrador de impostos"],correctIndex:2,explanation:"Paulo era fariseu, estudante de Gamaliel, e perseguia a Igreja até sua conversão no caminho de Damasco.",reference:"Atos 9:1-4; Filipenses 3:5-6",category:.geral,propheticMeaning:"A conversão dramática de Paulo é prova viva da ressurreição — ele deu sua vida pelo Cristo que antes perseguia."),
QuizQuestion(id:243,question:"Quais são os quatro Evangelhos?",options:["Mateus, Marcos, Lucas, João","Mateus, Marcos, Lucas, Atos","João, Pedro, Paulo, Tiago","Mateus, João, Tiago, Paulo"],correctIndex:0,explanation:"Os quatro Evangelhos canônicos são: Mateus, Marcos, Lucas e João — quatro perspectivas sobre a vida, morte e ressurreição de Jesus.",reference:"Mateus, Marcos, Lucas, João",category:.geral,propheticMeaning:"Os quatro Evangelhos correspondem às quatro faces das criaturas viventes de Ezequiel 1: leão (Mateus), boi (Marcos), homem (Lucas), águia (João)."),
QuizQuestion(id:244,question:"Qual é o mandamento mais importante segundo Jesus?",options:["Não matarás","Amarás ao Senhor teu Deus de todo o coração","Honrarás pai e mãe","Não furtarás"],correctIndex:1,explanation:"Jesus disse que o maior mandamento é 'Amarás ao Senhor teu Deus de todo o coração, alma e mente', seguido de amar o próximo.",reference:"Mateus 22:37-38",category:.geral,propheticMeaning:"Jesus resumiu toda a Lei e os Profetas em dois mandamentos de amor — revelando que a essência de Deus é amor (1 Jo 4:8)."),
QuizQuestion(id:245,question:"O que é a Trindade?",options:["Três deuses separados","Um Deus em três Pessoas: Pai, Filho e Espírito Santo","Deus em três manifestações","Três níveis de perfeição"],correctIndex:1,explanation:"A Trindade é um único Deus que existe eternamente em três Pessoas distintas: Pai, Filho e Espírito Santo.",reference:"Mateus 28:19; 2 Coríntios 13:14",category:.geral,propheticMeaning:"No batismo de Jesus, a Trindade se revelou: o Filho foi batizado, o Pai falou, o Espírito desceu — fundamento de toda a redenção trinitária (Mt 3:16-17)."),
QuizQuestion(id:246,question:"Qual é o significado do batismo cristão?",options:["Purificação futura","União com Cristo na morte e ressurreição","Entrada para a família de Maria","Promessa de nunca pecar"],correctIndex:1,explanation:"O batismo é sinal da união com Cristo: morrer para o velho eu e ressurgir para nova vida em Cristo.",reference:"Romanos 6:3-4",category:.geral,propheticMeaning:"'Fomos batizados para a sua morte... a fim de que... andemos em novidade de vida' (Rm 6:3-4) — o batismo proclama o evangelho da morte e ressurreição."),
QuizQuestion(id:247,question:"Qual é o propósito da Ceia do Senhor?",options:["Repetir o sacrifício de Cristo","Proclamar a morte de Cristo até que ele venha","Garantir a salvação","Apenas celebrar a última ceia"],correctIndex:1,explanation:"Paulo ensina que ao participar da Ceia proclamamos a morte de Cristo até que ele venha — memorial, proclamação e antecipação.",reference:"1 Coríntios 11:26",category:.geral,propheticMeaning:"A Ceia olha para trás (cruz), para o presente (comunhão) e para a frente (volta de Cristo) — toda a história da redenção numa mesa."),
QuizQuestion(id:248,question:"Qual é a 'Grande Comissão'?",options:["Ir a Jerusalém e esperar","'Ide e fazei discípulos de todas as nações'","Guardar o sábado","Construir templos"],correctIndex:1,explanation:"Mateus 28:18-20: 'Ide, fazei discípulos de todas as nações, batizando-os e ensinando-os a guardar tudo o que vos ordenei.'",reference:"Mateus 28:18-20",category:.geral,propheticMeaning:"A Grande Comissão cumpre a promessa a Abraão: 'em ti serão benditas todas as nações' (Gn 12:3) — a bênção chegando a todos por meio da Igreja."),
QuizQuestion(id:249,question:"Qual é o fruto do Espírito Santo segundo Gálatas 5?",options:["Saúde, riqueza e prosperidade","Amor, alegria, paz, longanimidade, benignidade, bondade, fidelidade, mansidão, domínio próprio","Línguas, profecia e cura","Oração, jejum e leitura"],correctIndex:1,explanation:"Gálatas 5:22-23 lista os nove frutos do Espírito que caracterizam a vida transformada pelo Espírito.",reference:"Gálatas 5:22-23",category:.geral,propheticMeaning:"O fruto do Espírito é o caráter de Cristo reproduzido no crente — cumprimento da nova aliança: 'porei minha lei no coração' (Jr 31:33)."),
QuizQuestion(id:250,question:"O que significa ser 'nascido de novo'?",options:["Ser rebatizado","Ser regenerado pelo Espírito Santo","Seguir rituais da Igreja","Tomar nova decisão moral"],correctIndex:1,explanation:"Jesus disse a Nicodemos: 'O que não nascer de novo não pode ver o reino de Deus' — nascimento sobrenatural pelo Espírito Santo.",reference:"João 3:3-7",category:.geral,propheticMeaning:"Nascer de novo cumpre Ezequiel 36:26-27: 'Porei dentro de vós um espírito novo' — a transformação profetizada agora disponível em Cristo."),
QuizQuestion(id:251,question:"Qual apóstolo foi chamado de 'pedra' por Jesus?",options:["João","Tiago","Pedro","André"],correctIndex:2,explanation:"Jesus disse a Simão: 'Tu és Pedro, e sobre esta pedra edificarei a minha Igreja.' Pedro liderou a Igreja primitiva e pregou no Pentecostes.",reference:"Mateus 16:18; Atos 2:14",category:.geral,propheticMeaning:"Pedro, que negou Jesus três vezes, foi restaurado por três afirmações de amor (Jo 21:15-17) — modelo da graça restauradora de Cristo."),
QuizQuestion(id:252,question:"Qual discípulo traiu Jesus?",options:["Tomé","Mateus","Judas Iscariotes","Simão Zelote"],correctIndex:2,explanation:"Judas Iscariotes entregou Jesus por trinta moedas de prata, cumprindo a profecia de Zacarias 11:12-13.",reference:"Mateus 26:14-16",category:.geral,propheticMeaning:"A traição de Judas cumpre o Salmo 41:9: 'O meu amigo íntimo... que comia do meu pão, levantou o calcanhar contra mim' — Davi prefigurou Cristo."),
QuizQuestion(id:253,question:"O que aconteceu no batismo de Jesus?",options:["Nada de especial","Os céus se abriram, o Espírito desceu como pomba e o Pai falou do céu","João o reconheceu antes de batizá-lo","Jesus orou no Getsêmani"],correctIndex:1,explanation:"No batismo de Jesus, a Trindade se manifestou: o Filho foi batizado, o Espírito desceu, o Pai falou.",reference:"Mateus 3:16-17",category:.geral,propheticMeaning:"O batismo de Jesus é o início de seu ministério messiânico ungido pelo Espírito, cumprindo Isaías 61:1-2."),
QuizQuestion(id:254,question:"Qual é o significado da ressurreição de Jesus?",options:["Apenas símbolo de esperança","Fundamento central: sem ela a fé é vã","Jesus era bom professor","Ponto opcional da fé"],correctIndex:1,explanation:"Paulo: 'Se Cristo não ressuscitou, é vã a nossa fé e ainda estais em vossos pecados' (1 Co 15:14-17).",reference:"1 Coríntios 15:14-17",category:.geral,propheticMeaning:"A ressurreição é 'as primícias dos que dormem' (1 Co 15:20) — garantia da ressurreição de todos os crentes."),
QuizQuestion(id:255,question:"Qual é a promessa de João 3:16?",options:["Cristãos nunca sofrerão","'Deus amou o mundo e deu seu Filho para que todo crente tenha vida eterna'","A Igreja será próspera","Deus dará saúde a quem crer"],correctIndex:1,explanation:"João 3:16: 'Deus amou o mundo de tal maneira que deu o seu Filho unigênito, para que todo crente não pereça, mas tenha a vida eterna.'",reference:"João 3:16",category:.geral,propheticMeaning:"'Deus amou o mundo' resume toda a história desde Gênesis — criação, queda, redenção. O 'Filho unigênito' cumpre o tipo de Isaque (Gn 22)."),
QuizQuestion(id:256,question:"O que é justificação pela fé?",options:["Ser justo pelas obras","Ser declarado justo por Deus mediante a fé em Cristo, não por obras","Praticar boas obras para merecer salvação","Seguir os mandamentos perfeitamente"],correctIndex:1,explanation:"Somos declarados justos diante de Deus não por mérito próprio, mas pela fé em Cristo que nos imputou sua justiça.",reference:"Romanos 3:28; 5:1",category:.geral,propheticMeaning:"Abraão foi justificado pela fé antes da circuncisão (Rm 4:10) — provando que esse sempre foi o caminho de Deus."),
QuizQuestion(id:257,question:"Qual é a promessa do Espírito Santo em João 14?",options:["O Espírito viria apenas para apóstolos","'O Pai enviará outro Consolador que ficará convosco para sempre'","O Espírito ensinaria apenas líderes","O Espírito viria no fim dos tempos"],correctIndex:1,explanation:"João 14:16-17: 'O Pai vos dará outro Consolador, para que fique convosco para sempre, o Espírito da verdade.'",reference:"João 14:16-17",category:.geral,propheticMeaning:"O Consolador prometido é o cumprimento da nova aliança — Deus habitando dentro dos crentes, transformando corações de pedra em carne (Ez 36:26)."),
QuizQuestion(id:258,question:"Qual Salmo começa com 'O Senhor é meu pastor'?",options:["Salmo 1","Salmo 23","Salmo 91","Salmo 121"],correctIndex:1,explanation:"O Salmo 23, de Davi, descreve Deus como o Pastor que guia, alimenta, restaura e protege suas ovelhas.",reference:"Salmos 23:1",category:.geral,propheticMeaning:"Jesus se identificou como 'o bom pastor que dá a vida pelas ovelhas' (Jo 10:11), cumprindo Ezequiel 34:23: 'Suscitarei um pastor que as apascentará.'"),
QuizQuestion(id:259,question:"Qual foi o primeiro milagre de Jesus em João?",options:["Curar um cego","Ressuscitar Lázaro","Transformar água em vinho em Caná","Andar sobre as águas"],correctIndex:2,explanation:"Jesus transformou água em vinho nas bodas de Caná da Galileia, revelando sua glória e a fé dos discípulos.",reference:"João 2:1-11",category:.geral,propheticMeaning:"Água (purificações judaicas) transformada em vinho simboliza a substituição da lei pela graça do Novo Pacto."),
QuizQuestion(id:260,question:"Quem escreveu o Apocalipse?",options:["Paulo","Pedro","João","Tiago"],correctIndex:2,explanation:"O apóstolo João escreveu o Apocalipse durante exílio na ilha de Patmos.",reference:"Apocalipse 1:1,9",category:.geral,propheticMeaning:"João, exilado por sua fé, recebe visão do Cristo glorificado — o Cordeiro que foi morto agora reina sobre todos os impérios."),
QuizQuestion(id:261,question:"O que é a 'Nova Jerusalém' em Apocalipse 21?",options:["Jerusalém reconstruída","Capital da Igreja hoje","Cidade celestial que descerá do céu — habitação eterna de Deus com os homens","Símbolo da Igreja no mundo"],correctIndex:2,explanation:"Apocalipse 21 descreve a Nova Jerusalém descendo do céu — sem morte, pranto ou dor.",reference:"Apocalipse 21:1-4",category:.geral,propheticMeaning:"A Nova Jerusalém é o cumprimento do projeto de Deus: 'O tabernáculo de Deus está com os homens' (Ap 21:3) — Éden restaurado para família incontável de toda nação."),
QuizQuestion(id:262,question:"O que Paulo ensina em 1 Coríntios 13 sobre o amor?",options:["O amor é sentimento passageiro","O amor é o maior: paciente, benigno, nunca perece","O amor é exclusivo para crentes","O amor só existe no casamento"],correctIndex:1,explanation:"1 Coríntios 13 descreve o amor como a maior virtude: paciente, benigno, não invejoso, suporta tudo, jamais perece.",reference:"1 Coríntios 13:4-8",category:.geral,propheticMeaning:"O amor de 1 Co 13 é o caráter de Cristo — cada qualidade é demonstrada por Jesus na cruz."),
QuizQuestion(id:263,question:"O que Jesus quis dizer com 'Eu sou o caminho, a verdade e a vida'?",options:["Ele mostraria o caminho para uma vida boa","Ele é o único meio ao Pai, revelação de Deus e fonte da vida eterna","Qualquer caminho sincero leva a Deus","A verdade é relativa"],correctIndex:1,explanation:"João 14:6: 'Eu sou o caminho, a verdade e a vida; ninguém vem ao Pai senão por mim.'",reference:"João 14:6",category:.geral,propheticMeaning:"'Eu Sou' (ego eimi) ecoa o Nome divino de Êxodo 3:14 — Jesus afirmando ser o mesmo YHWH do AT tomando forma humana."),
QuizQuestion(id:264,question:"O que é a 'segunda vinda' de Cristo?",options:["Sua ressurreição","Retorno glorioso para julgar, ressuscitar os mortos e estabelecer seu reino eterno","Sua presença espiritual na Igreja","O Pentecostes"],correctIndex:1,explanation:"A segunda vinda é o retorno pessoal, visível e glorioso de Jesus Cristo para completar sua obra redentora.",reference:"Atos 1:11; 1 Tessalonicenses 4:16",category:.geral,propheticMeaning:"Sua segunda vinda cumprirá todas as profecias do AT sobre o Messias reinando em glória que não se cumpriram na primeira."),
QuizQuestion(id:265,question:"Qual é a definição bíblica de fé em Hebreus 11:1?",options:["Acreditar sem evidências","'A fé é o firme fundamento das coisas que se esperam e a prova das que não se veem'","Sentir a presença de Deus","Fazer obras religiosas"],correctIndex:1,explanation:"Hebreus 11:1: 'A fé é o firme fundamento das coisas que se esperam, e a prova das coisas que não se veem.'",reference:"Hebreus 11:1",category:.geral,propheticMeaning:"A fé bíblica não é acreditar sem razão, mas agir sobre evidências passadas de Deus — como os heróis de Hebreus 11 que agiram sobre promessas ainda não cumpridas."),
QuizQuestion(id:266,question:"O que é o pecado original?",options:["O primeiro pecado de Caim","A desobediência de Adão que trouxe morte e separação de Deus para toda a humanidade","Os pecados de Israel no deserto","A Torre de Babel"],correctIndex:1,explanation:"O pecado de Adão (Gn 3) trouxe morte espiritual e física para toda a humanidade — a raiz de toda necessidade de redenção.",reference:"Gênesis 3:6-7; Romanos 5:12",category:.geral,propheticMeaning:"'Por um homem entrou o pecado... assim também por um homem veio a ressurreição dos mortos' (Rm 5:12; 1 Co 15:21) — Adão trouxe morte, Cristo trouxe vida."),
QuizQuestion(id:267,question:"Qual é a promessa de Romanos 8:28?",options:["Cristãos nunca sofrerão","'Todas as coisas contribuem para o bem daqueles que amam a Deus'","Deus responderá orações imediatamente","Cristãos serão prósperos"],correctIndex:1,explanation:"Romanos 8:28: 'Todas as coisas contribuem juntamente para o bem daqueles que amam a Deus, chamados segundo o seu propósito.'",reference:"Romanos 8:28",category:.geral,propheticMeaning:"'Todas as coisas' inclui o sofrimento — como a venda de José resultou em salvação. Deus soberanamente orquestra até os males para cumprir seu propósito redentor."),
QuizQuestion(id:268,question:"O que é a graça de Deus?",options:["Favor para quem merece","Favor imerecido para pecadores — salvação como dom, não por obras","Paciência com o pecado","A lei de Deus"],correctIndex:1,explanation:"Graça é o favor imerecido: 'pela graça sois salvos, mediante a fé, e isso não vem de vós; é dom de Deus; não de obras' (Ef 2:8-9).",reference:"Efésios 2:8-9",category:.geral,propheticMeaning:"A graça atravessa toda a Bíblia: Deus vestindo Adão e Eva (Gn 3:21), preservando Noé, chamando Abraão — sempre iniciativa de Deus para com os indignos."),
QuizQuestion(id:269,question:"Qual é a promessa de 1 João 1:9?",options:["'Se pedirmos muito, seremos perdoados'","'Se confessarmos os pecados, ele é fiel e justo para nos perdoar e purificar'","'O perdão é automático'","'Precisamos pagar pelos pecados'"],correctIndex:1,explanation:"1 João 1:9: 'Se confessarmos os nossos pecados, ele é fiel e justo para nos perdoar e purificar de toda injustiça.'",reference:"1 João 1:9",category:.geral,propheticMeaning:"O perdão é baseado na 'fidelidade e justiça' de Deus — Cristo pagou pelos pecados, então Deus deve perdoar o que confessa, sendo injusto cobrar duas vezes."),
QuizQuestion(id:270,question:"O que é a Transfiguração de Jesus?",options:["O batismo no Jordão","Jesus apareceu em glória com Moisés e Elias, e o Pai falou do céu","A ressurreição de Lázaro","A tentação no deserto"],correctIndex:1,explanation:"Na Transfiguração, Jesus apareceu em glória resplandecente com Moisés e Elias, e o Pai disse: 'Este é meu Filho amado.'",reference:"Mateus 17:1-5",category:.geral,propheticMeaning:"Moisés (Lei) e Elias (Profetas) conversando com Jesus confirma que ele é o cumprimento de tudo que a Lei e os Profetas anunciaram."),
QuizQuestion(id:271,question:"Qual é a promessa de Jeremias 29:11?",options:["Nunca haverá sofrimento","'Tenho pensamentos de paz e não de mal, para vos dar um futuro e uma esperança'","Israel nunca seria exilado","Prosperidade material garantida"],correctIndex:1,explanation:"Jeremias 29:11, dita a israelitas no exílio: 'Eu sei os pensamentos que tenho a vosso respeito — de paz e não de mal, para vos dar futuro e esperança.'",reference:"Jeremias 29:11",category:.geral,propheticMeaning:"A promessa foi dada em exílio — nas piores circunstâncias. O cumprimento máximo é Cristo, nosso 'futuro e esperança viva' (1 Pe 1:3)."),
QuizQuestion(id:272,question:"Qual é o significado do Pentecostes cristão?",options:["Celebração da criação","Derramamento do Espírito Santo, cumprimento de Joel 2 e nascimento da Igreja","A ressurreição de Jesus","A ascensão de Cristo"],correctIndex:1,explanation:"Em Atos 2, cinquenta dias após a Páscoa, o Espírito Santo foi derramado sobre os discípulos em Jerusalém.",reference:"Atos 2:1-4",category:.geral,propheticMeaning:"O Pentecostes cumpre a nova aliança: o Espírito agora habita nos crentes como templos vivos (1 Co 6:19), não apenas no templo físico."),
QuizQuestion(id:273,question:"Qual é a promessa de Apocalipse 21:4?",options:["Todos serão salvos","'Deus limpará toda lágrima; não haverá mais morte, pranto, clamor ou dor'","A Igreja reinará na terra","O pecado será perdoado futuramente"],correctIndex:1,explanation:"Apocalipse 21:4: 'Deus limpará dos seus olhos toda lágrima; e não haverá mais morte, nem pranto, nem clamor, nem dor.'",reference:"Apocalipse 21:4",category:.geral,propheticMeaning:"De Gênesis 3 (entrada da dor) a Apocalipse 21 (eliminação da dor) — Cristo na cruz absorveu toda a dor para que seus remidos nunca mais sofram."),
QuizQuestion(id:274,question:"Quais são as sete igrejas do Apocalipse?",options:["Roma, Atenas, Corinto, Éfeso, Jerusalém, Antioquia, Damasco","Éfeso, Esmirna, Pérgamo, Tiatira, Sardes, Filadélfia, Laodicéia","Jerusalém, Samaria, Antioquia, Corinto, Roma, Galácia, Tessalônica","Éfeso, Corinto, Roma, Galácia, Filipos, Colossas, Tessalônica"],correctIndex:1,explanation:"As sete igrejas do Apocalipse 2-3 são: Éfeso, Esmirna, Pérgamo, Tiatira, Sardes, Filadélfia e Laodicéia.",reference:"Apocalipse 1:11",category:.geral,propheticMeaning:"As sete igrejas representam padrões de espiritualidade presentes em todas as épocas — cada uma recebendo diagnóstico espiritual do Cristo glorificado."),
QuizQuestion(id:275,question:"O que Paulo diz sobre a ressurreição em 1 Coríntios 15?",options:["Ressurreição é apenas espiritual","Cristo ressuscitou corporalmente como primícias garantindo a ressurreição de todos os crentes","Apenas almas ressuscitam","A ressurreição já aconteceu completamente"],correctIndex:1,explanation:"1 Coríntios 15 defende a ressurreição corporal de Cristo como fato histórico e garantia da ressurreição de todos os crentes.",reference:"1 Coríntios 15:20-23",category:.geral,propheticMeaning:"Cristo ressurreto como 'primícias' é a primeira colheita que garante toda a colheita — cumprindo a esperança de Jó: 'em minha carne verei a Deus' (Jó 19:26)."),
QuizQuestion(id:276,question:"Qual é o significado da Páscoa judaica em relação a Cristo?",options:["É apenas festa cultural","O cordeiro pascal prefigura Cristo, o Cordeiro de Deus que tira o pecado","A Páscoa foi substituída pelo Natal","A Páscoa se cumpre no Pentecostes"],correctIndex:1,explanation:"O cordeiro pascal do Êxodo (Ex 12) — sem defeito, cujo sangue protegia da morte — é tipo direto de Cristo sacrificado na Páscoa.",reference:"Êxodo 12:1-13; 1 Coríntios 5:7",category:.geral,propheticMeaning:"Jesus morreu exatamente durante a Páscoa, quando cordeiros eram sacrificados no templo — o Pai sincronizou o calendário para que tipo e cumprimento coincidissem."),
QuizQuestion(id:277,question:"Qual é a promessa de Filipenses 4:13?",options:["'Tudo posso comprar'","'Tudo posso naquele que me fortalece'","'Tudo posso com fé suficiente'","'Tudo posso guardando a lei'"],correctIndex:1,explanation:"Filipenses 4:13: 'Tudo posso naquele que me fortalece' — Paulo escreveu isso na prisão, sobre contentamento em qualquer circunstância.",reference:"Filipenses 4:13",category:.geral,propheticMeaning:"O contexto é 'aprendi a estar contente em qualquer estado' (v.11) — promessa de fortaleza espiritual em qualquer situação, não de sucesso mundano."),
QuizQuestion(id:278,question:"O que Jesus ensinou sobre perdão em Mateus 6:14-15?",options:["Podemos perdoar quando sentirmos vontade","'Se perdoardes os homens, também vosso Pai vos perdoará; se não perdoardes, também não sereis perdoados'","O perdão é automático para cristãos","Só perdoamos quem pede perdão"],correctIndex:1,explanation:"Mateus 6:14-15 liga o perdão humano ao perdão divino — quem experimentou o perdão real, perdoa.",reference:"Mateus 6:14-15",category:.geral,propheticMeaning:"Jesus liga perdão horizontal ao vertical — não como condição para merecer o perdão de Deus, mas como evidência de que o recebemos verdadeiramente."),
QuizQuestion(id:279,question:"Qual é o significado do Nome YHWH?",options:["Deus criador","'EU SOU O QUE SOU' — o Deus eternamente existente e autoexistente","Deus guerreiro","Deus de misericórdia"],correctIndex:1,explanation:"YHWH vem do hebraico 'ser' e foi explicado a Moisés como 'EU SOU O QUE SOU' (Êx 3:14) — o Deus eternamente autoexistente.",reference:"Êxodo 3:14",category:.geral,propheticMeaning:"Jesus usou 'Eu Sou' (ego eimi) em João (6:35; 8:12; 10:9; 11:25; 14:6; 15:1), ecoando o Nome divino e afirmando ser o YHWH do AT."),
QuizQuestion(id:280,question:"Qual é a promessa de Isaías 40:31?",options:["'Curados de toda doença'","'Os que esperam no Senhor renovarão forças, subirão com asas como águias'","'Nunca terão necessidade'","'Viverão 120 anos'"],correctIndex:1,explanation:"Isaías 40:31: 'Os que esperam no Senhor renovarão as suas forças, subirão com asas como águias; correrão e não se cansarão.'",reference:"Isaías 40:31",category:.geral,propheticMeaning:"A renovação de forças é para 'os que esperam (qavah) no Senhor' — espera ativa com expectativa, possível pelo Espírito Santo que nos sustenta."),
QuizQuestion(id:281,question:"Qual é o mandamento novo de Jesus em João 13:34?",options:["Amar a Deus acima de tudo","'Que vos ameis uns aos outros como eu vos amei'","Guardar o sábado","Orar sem cessar"],correctIndex:1,explanation:"João 13:34: 'Um mandamento novo vos dou: Que vos ameis uns aos outros; assim como eu vos amei.'",reference:"João 13:34",category:.geral,propheticMeaning:"O amor é 'novo' pelo padrão: 'como eu vos amei' — o amor sacrificial da cruz transforma o amor de sentimento em escolha baseada no modelo de Cristo."),
QuizQuestion(id:282,question:"O que aconteceu com Paulo no caminho de Damasco?",options:["Ele foi batizado","Jesus ressurreto apareceu a ele em luz e o chamou ao apostolado","Ele encontrou Pedro","Ele leu as Escrituras e se converteu"],correctIndex:1,explanation:"Jesus ressurreto apareceu a Paulo em luz brilhante no caminho de Damasco, chamando-o pelo nome e comissionando-o como apóstolo aos gentios.",reference:"Atos 9:3-6",category:.geral,propheticMeaning:"A conversão de Paulo pela aparição do Ressurreto é uma das maiores provas da ressurreição — ninguém se entrega à morte por uma mentira que ele mesmo inventou."),
QuizQuestion(id:283,question:"Quais são os três maiores dons em 1 Coríntios 13:13?",options:["Fé, poder e sabedoria","Fé, esperança e amor — e o maior é o amor","Oração, jejum e esmola","Línguas, profecia e discernimento"],correctIndex:1,explanation:"1 Coríntios 13:13: 'Agora pois permanecem a fé, a esperança e o amor, estes três; mas o maior destes é o amor.'",reference:"1 Coríntios 13:13",category:.geral,propheticMeaning:"O amor é o maior porque permanece eternamente — fé e esperança se cumprem na visão direta de Deus, mas o amor nunca tem fim (1 Co 13:8)."),
QuizQuestion(id:284,question:"O que é a justificação, santificação e glorificação?",options:["Três denominações cristãs","Três etapas da salvação: declarado justo, transformado em caráter, glorificado na ressurreição","Três sacramentos da Igreja","Três dons do Espírito Santo"],correctIndex:1,explanation:"As três etapas da salvação: justificação (declarados justos pela fé), santificação (transformados pelo Espírito), glorificação (ressurreição no fim).",reference:"Romanos 8:30",category:.geral,propheticMeaning:"Romanos 8:30 une as três: 'Os que predestinou, também chamou; os que chamou, também justificou; os que justificou, também glorificou' — toda a salvação é obra de Deus."),
QuizQuestion(id:285,question:"Qual é a promessa de Mateus 11:28?",options:["'Pedis e recebereis'","'Vinde a mim, todos os que estais cansados e sobrecarregados, e eu vos darei descanso'","'Buscai e achareis'","'Permanecei em mim'"],correctIndex:1,explanation:"Mateus 11:28: 'Vinde a mim, todos os que estais cansados e sobrecarregados, e eu vos darei descanso.'",reference:"Mateus 11:28",category:.geral,propheticMeaning:"O descanso que Jesus oferece cumpre o tipo do shabat — o descanso final de Deus ao qual Hebreus 4 aponta: entrar no repouso de Deus pela fé em Cristo."),
QuizQuestion(id:286,question:"Qual é o 'pecado contra o Espírito Santo'?",options:["Blasfemar em nome de Deus","A recusa persistente e deliberada de atribuir a obra de Deus ao diabo, endurecendo o coração contra o evangelho","Não ir à Igreja","Mentir uma vez"],correctIndex:1,explanation:"Jesus disse que a blasfêmia contra o Espírito Santo — atribuir ao diabo o que é obra do Espírito — não seria perdoada, por endurecer o coração contra a graça.",reference:"Mateus 12:31-32",category:.geral,propheticMeaning:"O pecado imperdoável é o único que fecha a porta à fé — não porque Deus não queira perdoar, mas porque o coração que comete esse pecado rejeita o único meio de perdão: o Espírito que aplica a obra de Cristo."),
QuizQuestion(id:287,question:"Qual é a parábola do Filho Pródigo sobre?",options:["A importância da obediência","O amor do pai que acolhe o filho arrependido — imagem do amor de Deus pelos pecadores","A riqueza e pobreza","Os perigos da idolatria"],correctIndex:1,explanation:"A parábola do Filho Pródigo (Lc 15:11-32) mostra o pai correndo ao encontro do filho arrependido, símbolo do amor de Deus pelos pecadores que retornam.",reference:"Lucas 15:11-32",category:.geral,propheticMeaning:"O pai correndo ao filho ainda 'de longe' revela que Deus nos busca antes de chegarmos — a graça precede o arrependimento."),
QuizQuestion(id:288,question:"O que Jesus ensinou sobre a oração no Sermão do Monte?",options:["Orar em público para ser visto","Orar em secreto ao Pai que vê em segredo, usando o modelo do Pai Nosso","Repetir muitas palavras","Orar apenas em grupo"],correctIndex:1,explanation:"Jesus ensinou a orar em secreto ao Pai (Mt 6:6) e deu o modelo do 'Pai Nosso' como forma de orar.",reference:"Mateus 6:6-13",category:.geral,propheticMeaning:"A oração 'Pai Nosso' revela o privilégio da nova aliança: acessar a Deus como Pai é o direito dos filhos adotados por Cristo (Gl 4:6)."),
QuizQuestion(id:289,question:"Qual é o significado do Sermão do Monte?",options:["Um discurso político de Jesus","O maior ensino moral da história: as Bem-aventuranças e a ética do Reino de Deus","Um conjunto de regras para merecer salvação","O testamento final de Jesus"],correctIndex:1,explanation:"O Sermão do Monte (Mt 5-7) contém as Bem-aventuranças e ensina a ética do Reino — não para merecer salvação, mas para viver conforme a natureza do Reino.",reference:"Mateus 5-7",category:.geral,propheticMeaning:"Jesus no Monte (como Moisés no Sinai) entregando a nova lei do Reino mostra que ele é o novo Moisés — não abolindo a lei, mas cumprindo-a e internalizando-a (Mt 5:17)."),
QuizQuestion(id:290,question:"Quem eram os fariseus no tempo de Jesus?",options:["Sacerdotes do templo","Líderes religiosos que ensinavam a lei oral e eram conhecidos pelo legalismo","Soldados romanos","Cobradores de impostos"],correctIndex:1,explanation:"Fariseus eram líderes religiosos judeus que enfatizavam a lei oral além da escrita, frequentemente criticados por Jesus pela hipocrisia e legalismo.",reference:"Mateus 23:1-7",category:.geral,propheticMeaning:"O legalismo dos fariseus contrasta com a graça de Cristo — a lei externa vs. a transformação interna que somente o Espírito pode operar (Jr 31:33; Ez 36:26)."),
QuizQuestion(id:291,question:"O que é a parábola do Bom Samaritano?",options:["Uma história sobre higiene ritual","Jesus ensinando que o 'próximo' é qualquer pessoa necessitada, independente de etnia ou religião","Uma crítica aos sacerdotes de Israel","Uma história sobre como pagar impostos"],correctIndex:1,explanation:"A parábola do Bom Samaritano (Lc 10:30-37) responde 'quem é o meu próximo?' — mostrando que amor ao próximo transcende fronteiras étnicas e religiosas.",reference:"Lucas 10:30-37",category:.geral,propheticMeaning:"O Samaritano — desprezado pelos judeus — sendo o herói da parábola antecipa a inclusão dos gentios no povo de Deus e o caráter universal do evangelho."),
QuizQuestion(id:292,question:"Qual é a parábola das dez virgens sobre?",options:["Sobre o casamento judaico","Sobre estar preparado para a vinda do noivo (Cristo) com suficiente óleo (Espírito Santo)","Sobre a pureza das mulheres","Sobre economizar recursos"],correctIndex:1,explanation:"As dez virgens (Mt 25:1-13): cinco sábias tinham óleo suficiente para esperar o noivo; cinco tolas não tinham. Jesus ensina a estar preparado para sua vinda.",reference:"Mateus 25:1-13",category:.geral,propheticMeaning:"O óleo é frequentemente tipo do Espírito Santo — não podemos 'emprestar' a graça de outro; cada um precisa de sua própria relação com o Espírito."),
QuizQuestion(id:293,question:"Qual é a parábola dos talentos?",options:["Sobre ter habilidades musicais","Sobre usar bem o que Deus nos deu, pois daremos conta diante de Cristo","Sobre guardar dinheiro com segurança","Sobre pagar dívidas"],correctIndex:1,explanation:"A parábola dos talentos (Mt 25:14-30): servos que multiplicaram os talentos foram recompensados; o que escondeu por medo foi julgado.",reference:"Mateus 25:14-30",category:.geral,propheticMeaning:"Os 'talentos' representam todos os dons, recursos e oportunidades que Deus nos confia — a mordomia cristã exige investir para o Reino, não guardar por medo."),
QuizQuestion(id:294,question:"O que é o Sermão da Montanha das Oliveiras?",options:["O Sermão do Monte","O discurso profético de Jesus sobre a destruição de Jerusalém e sua segunda vinda","A oração de Jesus no Getsêmani","O discurso sobre as bem-aventuranças"],correctIndex:1,explanation:"O Discurso das Oliveiras (Mt 24; Mc 13; Lc 21) contém as profecias de Jesus sobre a destruição do templo e sinais de sua volta.",reference:"Mateus 24:1-3",category:.geral,propheticMeaning:"Jesus profetizou com precisão a destruição de Jerusalém em 70 d.C. — cumprida literalmente — dando credibilidade a suas profecias ainda futuras sobre sua segunda vinda."),
QuizQuestion(id:295,question:"Qual foi o julgamento de Jesus antes da crucificação?",options:["Apenas julgado pelo Sinédrio","Julgado pelo Sinédrio (acusação religiosa) e por Pilatos (sentença romana)","Julgado apenas por Pilatos","Julgado por Herodes Antipas"],correctIndex:1,explanation:"Jesus passou por múltiplos julgamentos: noturno pelo Sinédrio, por Pilatos (governador romano) e por Herodes Antipas, retornando a Pilatos que ordenou a crucificação.",reference:"Mateus 26:57; 27:1-2; Lucas 23:6-12",category:.geral,propheticMeaning:"O julgamento injusto de Jesus cumpre Isaías 53:8: 'Por opressão e por juízo foi tirado' — o inocente condenado pelo culpado é a essência da substituição."),
QuizQuestion(id:296,question:"Quantas horas Jesus ficou na cruz?",options:["Três horas","Seis horas","Doze horas","Vinte e quatro horas"],correctIndex:1,explanation:"Jesus foi crucificado às 9h da manhã e morreu às 3h da tarde (hora nona) — seis horas na cruz (Mc 15:25,34).",reference:"Marcos 15:25,34",category:.geral,propheticMeaning:"Das 12h às 15h (hora sexta à nona), trevas cobriram a terra — 3 horas de trevas na crucificação cumprindo o julgamento cósmico de Amós 8:9: 'Farei o sol pôr-se ao meio-dia.'"),
QuizQuestion(id:297,question:"O que rasgou-se no templo quando Jesus morreu?",options:["A porta do templo","O véu do templo de cima a baixo","O teto do templo","A arca da aliança foi destruída"],correctIndex:1,explanation:"No momento da morte de Jesus, o véu do templo (que separava o Santo dos Santos) rasgou-se de cima a baixo.",reference:"Mateus 27:51",category:.geral,propheticMeaning:"O véu rasgado por Deus (de cima para baixo) simboliza que o acesso ao Pai foi aberto por Cristo — 'temos ousadia para entrar no lugar santíssimo pelo sangue de Jesus' (Hb 10:19)."),
QuizQuestion(id:298,question:"Quem encontrou o sepulcro vazio no domingo de manhã?",options:["Pedro e João apenas","As mulheres (incluindo Maria Madalena) foram as primeiras testemunhas do sepulcro vazio","Todos os apóstolos juntos","Os guardas romanos"],correctIndex:1,explanation:"Maria Madalena e outras mulheres foram ao sepulcro ao amanhecer do domingo e encontraram a pedra rolada e o túmulo vazio.",reference:"João 20:1-2; Mateus 28:1-6",category:.geral,propheticMeaning:"As mulheres como primeiras testemunhas da ressurreição é detalhe que nenhum inventor faria — na cultura do 1º séc., mulheres não eram aceitas como testemunhas legais. A Igreja primitiva não inventaria isso."),
QuizQuestion(id:299,question:"O que Jesus fez durante os 40 dias entre a ressurreição e a ascensão?",options:["Ficou escondido dos discípulos","Apareceu a muitas pessoas e ensinou sobre o Reino de Deus","Voltou para o Egito","Ficou apenas com Pedro"],correctIndex:1,explanation:"Durante 40 dias, Jesus ressurreto apareceu a mais de 500 pessoas (1 Co 15:6), ensinando sobre o Reino e preparando os discípulos.",reference:"Atos 1:3; 1 Coríntios 15:6",category:.geral,propheticMeaning:"Os 40 dias de aparições ressurretas criam uma das maiores bases de evidência históricas — mais de 500 testemunhas oculares simultâneas são impossíveis de explicar como alucinação coletiva."),
QuizQuestion(id:300,question:"O que é a Ascensão de Jesus?",options:["A subida ao monte da Transfiguração","Jesus subindo visivelmente aos céus 40 dias após a ressurreição","Jesus indo ao céu ao morrer","A volta de Jesus ao terceiro dia"],correctIndex:1,explanation:"Quarenta dias após a ressurreição, Jesus ascendeu visivelmente aos céus diante dos discípulos no Monte das Oliveiras.",reference:"Atos 1:9-11",category:.geral,propheticMeaning:"A Ascensão cumpre o Salmo 110:1: 'Disse o Senhor ao meu Senhor: senta-te à minha direita' — Jesus assumiu o trono cósmico como Rei-Sacerdote eterno."),
QuizQuestion(id:301,question:"O que são as epístolas do NT?",options:["Livros históricos","Cartas escritas por apóstolos a igrejas e indivíduos — Paulo, Pedro, João, Tiago, Judas","Os quatro Evangelhos","Profecias sobre o fim dos tempos"],correctIndex:1,explanation:"As epístolas são 21 cartas apostólicas: 13 de Paulo, 1 de Hebreus (autoria debatida), e as cartas gerais de Tiago, Pedro, João e Judas.",reference:"Romanos a Judas",category:.geral,propheticMeaning:"As epístolas aplicam a obra de Cristo às situações práticas da Igreja — teologia encarnada no dia a dia, mostrando como o evangelho transforma toda a vida."),
QuizQuestion(id:302,question:"Qual é o tema da carta aos Romanos?",options:["Organização da Igreja","O evangelho: justificação pela fé, não por obras — a mais completa exposição da salvação no NT","Os dons espirituais","A segunda vinda de Cristo"],correctIndex:1,explanation:"Romanos apresenta a doutrina da justificação pela fé, a condição universal de pecado, a obra de Cristo e as implicações para judeus e gentios.",reference:"Romanos 1:16-17",category:.geral,propheticMeaning:"Romanos 1:17 — 'o justo viverá pela fé' — é a pedra angular da Reforma Protestante, revelando que a salvação sempre foi pela fé desde Abraão (Rm 4)."),
QuizQuestion(id:303,question:"O que Paulo ensina sobre a ressurreição do corpo em 1 Co 15:52?",options:["Que não haverá ressurreição do corpo","'Num momento, num abrir e fechar de olhos, ao som da última trombeta: os mortos ressuscitarão incorruptíveis'","Que apenas as almas ressuscitam","Que a ressurreição já aconteceu"],correctIndex:1,explanation:"1 Co 15:52: 'Num momento, num abrir e fechar de olhos, ao som da última trombeta, os mortos ressuscitarão incorruptíveis e nós seremos transformados.'",reference:"1 Coríntios 15:52",category:.geral,propheticMeaning:"A transformação 'num abrir e fechar de olhos' descreve o arrebatamento/ressurreição que Paulo também detalha em 1 Ts 4:16-17 — a esperança futura que consola o crente."),
QuizQuestion(id:304,question:"O que é a 'espinha na carne' que Paulo menciona?",options:["Uma doença nos olhos","Uma fraqueza ou sofrimento crônico que Deus permitiu para manter Paulo humilde","Um perseguidor específico","Uma tentação sexual"],correctIndex:1,explanation:"Paulo descreve uma 'espinha na carne' não removida por Deus após três pedidos, para que a graça de Deus se manifestasse em sua fraqueza.",reference:"2 Coríntios 12:7-9",category:.geral,propheticMeaning:"Deus responde: 'A minha graça te basta' — a fraqueza humana é o palco onde a graça divina brilha mais. Paulo aprendeu a 'gloriar-se nas fraquezas' (2 Co 12:9)."),
QuizQuestion(id:305,question:"Qual carta Paulo escreveu na prisão?",options:["Gálatas e Romanos","Efésios, Filipenses, Colossenses e Filemom (cartas da prisão)","1 e 2 Coríntios","Hebreus e Tiago"],correctIndex:1,explanation:"As quatro cartas da prisão de Paulo são: Efésios, Filipenses, Colossenses e Filemom — escritas durante sua prisão em Roma.",reference:"Efésios 3:1; Filipenses 1:13",category:.geral,propheticMeaning:"Paulo escrevendo sobre alegria e graça de dentro da prisão (Fp 4:4) é prova de que a paz de Cristo transcende as circunstâncias — 'aprendi a estar contente em qualquer estado' (Fp 4:11)."),
QuizQuestion(id:306,question:"Qual é o tema central de Gálatas?",options:["Organização da Igreja","A liberdade do evangelho: justificados por fé, não por obras da lei; contra o 'outro evangelho' dos judaizantes","Os dons espirituais","As regras do casamento cristão"],correctIndex:1,explanation:"Paulo defende com vigor o evangelho da graça: 'somos justificados pela fé em Cristo Jesus e não pelas obras da lei' (Gl 2:16).",reference:"Gálatas 2:16",category:.geral,propheticMeaning:"Gálatas 3:13: 'Cristo nos resgatou da maldição da lei, tendo-se feito maldição por nós' — a substituição penal expressa com máxima clareza."),
QuizQuestion(id:307,question:"O que é a 'carne' versus o 'Espírito' em Paulo?",options:["Corpo físico versus alma","A natureza pecaminosa versus a nova natureza em Cristo — a batalha espiritual interior do crente","Judeus versus gentios","O AT versus o NT"],correctIndex:1,explanation:"Paulo descreve a batalha entre a 'carne' (natureza caída) e o 'Espírito' (nova natureza) no crente — o Espírito traz vida e paz; a carne traz morte.",reference:"Romanos 8:5-6; Gálatas 5:17",category:.geral,propheticMeaning:"A tensão carne/Espírito é resolvida definitivamente na ressurreição — quando receberemos corpo espiritual e a batalha interior cessará para sempre (1 Co 15:44)."),
QuizQuestion(id:308,question:"O que Paulo diz sobre o casamento em Efésios 5?",options:["O casamento é inferior ao celibato","O casamento é imagem de Cristo e a Igreja: o marido ama como Cristo; a esposa se submete como a Igreja","O casamento é contrato social","As mulheres devem trabalhar em casa"],correctIndex:1,explanation:"Efésios 5:22-33 descreve o casamento como mistério que reflete a relação de Cristo com a Igreja.",reference:"Efésios 5:25-32",category:.geral,propheticMeaning:"O casamento cristão é pregação visual do evangelho — o amor sacrificial do marido é sinal do amor de Cristo pela Igreja; a confiança da esposa é sinal da fé da Igreja em Cristo."),
QuizQuestion(id:309,question:"Qual é o tema da carta aos Hebreus?",options:["As regras da Igreja","A superioridade de Cristo sobre toda a religião do AT — sumo sacerdote eterno segundo Melquisedeque","A segunda vinda de Cristo","Os dons do Espírito Santo"],correctIndex:1,explanation:"Hebreus argumenta que Cristo é superior: aos anjos, a Moisés, ao sacerdócio levítico, ao tabernáculo, e que o NT supera o AT como cumprimento supera sombra.",reference:"Hebreus 1:1-3",category:.geral,propheticMeaning:"Hebreus 8:5 explica que o culto do AT era 'sombra' do celestial — cada sacrifício, sacerdote e tabernáculo era tipo de Cristo, o cumprimento definitivo."),
QuizQuestion(id:310,question:"Qual é o 'caminho mais excelente' de 1 Coríntios 12:31?",options:["Os dons espirituais","O amor, descrito no capítulo 13 — maior que todos os dons","A profecia","As línguas angelicais"],correctIndex:1,explanation:"Após listar os dons espirituais, Paulo diz 'mostro-vos um caminho mais excelente' e descreve o amor em 1 Co 13 — maior que qualquer dom.",reference:"1 Coríntios 12:31; 13:1",category:.geral,propheticMeaning:"Os dons sem amor são inúteis (1 Co 13:1-3) — o amor é o fruto do Espírito que autentica todos os dons e permanece quando os dons cessarem."),
QuizQuestion(id:311,question:"Quem foi Estêvão na Igreja primitiva?",options:["Um apóstolo","O primeiro mártir cristão, diácono cheio do Espírito que proclamou um longo sermão antes de ser apedrejado","Um sacerdote judeu","Um profeta"],correctIndex:1,explanation:"Estêvão, diácono cheio do Espírito Santo, proclamou um poderoso sermão sobre a história de Israel e foi apedrejado — o primeiro mártir cristão.",reference:"Atos 7:54-60",category:.geral,propheticMeaning:"Estêvão morrendo e dizendo 'Senhor Jesus, recebe meu espírito' e 'não lhes imputes este pecado' espelha Cristo na cruz — mortes paralelas que revelam o caráter transformador do Espírito."),
QuizQuestion(id:312,question:"Quem era Filipe nos Atos dos Apóstolos?",options:["O apóstolo Filipe","O evangelista que pregou em Samaria e batizou o etíope eunuco","Um sacerdote em Jerusalém","O pai de João Batista"],correctIndex:1,explanation:"Filipe, o evangelista, pregou com poder em Samaria e depois foi guiado pelo Espírito para evangelizar o eunuco etíope lendo Isaías 53.",reference:"Atos 8:5-39",category:.geral,propheticMeaning:"O eunuco lendo Isaías 53 e sendo guiado por Filipe ao seu cumprimento em Cristo é o padrão do evangelismo bíblico — partir das Escrituras e 'anunciar-lhe Jesus.'"),
QuizQuestion(id:313,question:"O que aconteceu quando Paulo e Silas estavam presos em Filipos?",options:["Eles ficaram em silêncio esperando ajuda","Oraram e cantaram hinos à meia-noite; um terremoto abriu as portas; o carcereiro se converteu","Fugiram pela janela","Um anjo os libertou"],correctIndex:1,explanation:"Paulo e Silas orando e cantando na prisão, o terremoto que abriu as portas, e a conversão do carcereiro formam um dos mais poderosos relatos de Atos.",reference:"Atos 16:25-34",category:.geral,propheticMeaning:"Presos cantando louvor é evidência de paz que 'excede o entendimento' (Fp 4:7) — a mesma paz que Paulo depois descreveria escrevendo de outra prisão romana."),
QuizQuestion(id:314,question:"O que Paulo pregou no Areópago de Atenas?",options:["Condenou a idolatria grega","Usou o altar 'Ao Deus desconhecido' como ponto de contato para apresentar o Deus criador e a ressurreição de Jesus","Discutiu filosofia sem mencionar Cristo","Pregou apenas para judeus"],correctIndex:1,explanation:"Em Atenas (At 17:22-34), Paulo usou o altar 'Ao Deus desconhecido' como ponto de contato, revelou o Deus criador e terminou com a ressurreição de Cristo.",reference:"Atos 17:22-31",category:.geral,propheticMeaning:"Paulo dialogando com a cultura grega sem comprometer o conteúdo do evangelho é modelo de evangelismo contextualizado — começando onde o ouvinte está, levando a Cristo."),
QuizQuestion(id:315,question:"Qual é a carta mais pessoal e íntima de Paulo?",options:["Romanos","Filemom — pedindo que um senhor receba seu escravo fugido como irmão em Cristo","Filipenses","1 Timóteo"],correctIndex:1,explanation:"Filemom é a carta mais pessoal de Paulo — um apelo íntimo pedindo que Filemom receba de volta seu escravo Onésimo como 'irmão amado' em Cristo.",reference:"Filemom 15-16",category:.geral,propheticMeaning:"Paulo pedindo que Filemom receba Onésimo 'não mais como escravo, mas... como irmão amado' é o evangelho subvertendo as estruturas sociais de dentro para fora."),
QuizQuestion(id:316,question:"O que é a 'armadura de Deus' em Efésios 6?",options:["Oração e jejum","Cinto da verdade, couraça da justiça, calçado do evangelho, escudo da fé, capacete da salvação, espada do Espírito","A Bíblia sozinha","Participação nos sacramentos"],correctIndex:1,explanation:"Efésios 6:13-17 lista seis peças da armadura espiritual para o cristão resistir ao diabo.",reference:"Efésios 6:13-17",category:.geral,propheticMeaning:"Toda a armadura é baseada em Cristo: ele é nossa Verdade (Jo 14:6), Justiça (2 Co 5:21), Evangelho (Rm 1:16), Fé (Hb 12:2), Salvação, e a Palavra encarnada (Jo 1:1)."),
QuizQuestion(id:317,question:"Qual é o tema da carta de Tiago?",options:["Justificação pela fé sem obras","A fé que se manifesta em obras — fé morta versus fé viva que transforma o comportamento","Os dons espirituais","A segunda vinda de Cristo"],correctIndex:1,explanation:"Tiago 2:26: 'Assim como o corpo sem o espírito é morto, assim também a fé sem obras é morta' — não contradizendo Paulo, mas completando.",reference:"Tiago 2:14-26",category:.geral,propheticMeaning:"Paulo e Tiago são complementares: Paulo fala da raiz (fé que salva), Tiago fala do fruto (obras que evidenciam a fé salva). Ambos citam Abraão como exemplo (Rm 4; Tg 2:21)."),
QuizQuestion(id:318,question:"Qual é a promessa de Tiago 1:5?",options:["'Pedis e recebereis tudo'","'Se alguém dentre vós necessita de sabedoria, peça-a a Deus, que a todos dá liberalmente, e ser-lhe-á dada'","'Deus dará riquezas'","'A saúde será restaurada'"],correctIndex:1,explanation:"Tiago 1:5: 'Se alguém necessita de sabedoria, peça-a a Deus, que a todos dá liberalmente e não lança em rosto, e ser-lhe-á dada.'",reference:"Tiago 1:5",category:.geral,propheticMeaning:"A sabedoria de Deus é Cristo: 'o qual se tornou para nós sabedoria da parte de Deus' (1 Co 1:30) — pedir sabedoria é buscar a mente de Cristo nas situações da vida."),
QuizQuestion(id:319,question:"O que Tiago ensina sobre a língua em Tiago 3?",options:["A língua é neutra","A língua é um fogo que pode inflamar toda a vida — ninguém consegue domá-la sem o Espírito","A língua deve ser usada para profecia","A língua é o maior dom espiritual"],correctIndex:1,explanation:"Tiago 3:6: 'A língua é um fogo... inflama o curso da vida.' Ela pode amaldiçoar ou bendizer, e sua doma requer o Espírito Santo.",reference:"Tiago 3:5-10",category:.geral,propheticMeaning:"Jesus ensinou que 'pela tua palavra serás justificado e pela tua palavra serás condenado' (Mt 12:37) — as palavras revelam o coração e a transformação interior."),
QuizQuestion(id:320,question:"O que Pedro ensina sobre o sofrimento em 1 Pedro?",options:["Cristãos nunca sofrerão","O sofrimento pelo bem é chamado por Deus e segue o exemplo de Cristo — que sofreu para nos trazer a Deus","O sofrimento é punição de Deus","O sofrimento é sinal de falta de fé"],correctIndex:1,explanation:"1 Pedro 2:21: 'Para isto mesmo fostes chamados, porque também Cristo sofreu em vosso lugar, deixando-vos exemplo para seguirdes os seus passos.'",reference:"1 Pedro 2:21; 4:12-13",category:.geral,propheticMeaning:"O sofrimento cristão 'participa dos sofrimentos de Cristo' (1 Pe 4:13) — não é punição mas participação, preparando para a glória que virá (Rm 8:18)."),
QuizQuestion(id:321,question:"O que João ensina sobre o amor em 1 João?",options:["Amor é sentimento","'Deus é amor. Nisto se manifestou o amor de Deus: enviou seu Filho unigênito ao mundo para vivermos por meio dele'","O amor depende de sermos amados primeiro","Amor é apenas ação, nunca sentimento"],correctIndex:1,explanation:"1 João 4:8-9: 'Deus é amor. Nisto se manifestou o amor de Deus: enviou seu Filho unigênito para vivermos por meio dele.'",reference:"1 João 4:8-9",category:.geral,propheticMeaning:"'Nós amamos porque ele nos amou primeiro' (1 Jo 4:19) — o amor cristão não é auto-gerado mas resposta ao amor de Deus revelado em Cristo na cruz."),
QuizQuestion(id:322,question:"O que Judas alerta sobre em sua carta?",options:["A falta de oração","Falsos mestres que introduzem heresias e vivem imoral, distorcendo a graça em libertinagem","A pobreza da Igreja","A falta de dons espirituais"],correctIndex:1,explanation:"Judas alerta para falsos mestres que introduzem heresias sorrateiramente, transformando a graça em libertinagem e negando Jesus Cristo.",reference:"Judas 3-4",category:.geral,propheticMeaning:"Judas exorta a 'combater pela fé uma vez dada aos santos' — a fé cristã tem conteúdo fixo que precisa ser defendido contra distorções em cada geração."),
QuizQuestion(id:323,question:"O que é o 'dia do Senhor' nas profecias bíblicas?",options:["O sábado judaico","O dia de domingo para adoração","O dia futuro de julgamento e intervenção divina — culminando na volta de Cristo","O dia de Pentecostes"],correctIndex:2,explanation:"O 'dia do Senhor' nos profetas e no NT refere-se ao dia de julgamento e intervenção divina na história, culminando no retorno de Cristo.",reference:"Amós 5:18-20; 1 Tessalonicenses 5:2",category:.geral,propheticMeaning:"Paulo em 1 Ts 5:2 diz que o Dia do Senhor virá como 'ladrão na noite' — incentivando vigilância e santidade, não especulação sobre datas."),
QuizQuestion(id:324,question:"Qual é a promessa do Salmo 46:10?",options:["'O Senhor é meu pastor'","'Aquietai-vos e sabei que eu sou Deus; serei exaltado entre as nações'","'Bem-aventurado o homem que não anda no conselho dos ímpios'","'O Senhor é a minha luz e salvação'"],correctIndex:1,explanation:"Salmo 46:10: 'Aquietai-vos e sabei que eu sou Deus; serei exaltado entre as nações, serei exaltado na terra.'",reference:"Salmos 46:10",category:.geral,propheticMeaning:"'Aquietai-vos' (raphah = relaxai, soltai) é o convite de Deus ao descanso na fé — o antídoto para a ansiedade humana é conhecer quem Deus é."),
QuizQuestion(id:325,question:"Qual é o primeiro versículo da Bíblia?",options:["'Eu sou o Senhor, teu Deus'","'No princípio criou Deus os céus e a terra'","'Ouve, ó Israel, o Senhor é nosso Deus'","'Feliz o homem que não anda no conselho dos ímpios'"],correctIndex:1,explanation:"Gênesis 1:1: 'No princípio criou Deus os céus e a terra.' — a declaração mais fundamental da Bíblia sobre a existência de Deus como Criador.",reference:"Gênesis 1:1",category:.geral,propheticMeaning:"João 1:1 ecoa Gênesis 1:1: 'No princípio era o Verbo' — o Cristo pré-existente que criou tudo (Jo 1:3) é o mesmo que veio ao mundo que havia criado."),
QuizQuestion(id:326,question:"Qual profeta antigo é mais citado no NT?",options:["Jeremias","Ezequiel","Isaías","Daniel"],correctIndex:2,explanation:"Isaías é o profeta do AT mais citado no NT — especialmente nos Evangelhos, com mais de 50 citações diretas.",reference:"Isaías; Mateus 1:22-23 et al.",category:.geral,propheticMeaning:"Isaías é chamado de 'o Evangelista do AT' — suas profecias messiânicas, especialmente o Servo Sofredor (Is 53), são tão claras que o NT as usa como pilar da cristologia."),
QuizQuestion(id:327,question:"Que evento marcou o início do ministério público de Jesus?",options:["O nascimento em Belém","O batismo no Rio Jordão e a tentação no deserto","A chamada dos doze discípulos","As bodas de Caná"],correctIndex:1,explanation:"O batismo de Jesus (ungimento pelo Espírito) e os 40 dias de tentação no deserto marcam o início de seu ministério público, seguidos do chamado dos discípulos.",reference:"Mateus 3:13-4:11",category:.geral,propheticMeaning:"Os 40 dias de Jesus no deserto vitorioso sobre a tentação revertem os 40 anos de Israel no deserto falhando na tentação — Jesus é o Israel fiel que cumpriu o que Israel não conseguiu."),
QuizQuestion(id:328,question:"Qual foi a última ceia de Jesus?",options:["Uma ceia de aniversário","A refeição da Páscoa onde Jesus instituiu o pão e o cálice como memória de seu corpo e sangue","Uma ceia em Betânia com Lázaro","O pão e o peixe que multiplicou"],correctIndex:1,explanation:"Na noite antes de sua crucificação, Jesus celebrou a Páscoa com os discípulos e instituiu a Ceia do Senhor com o pão e o cálice.",reference:"Mateus 26:26-29",category:.geral,propheticMeaning:"Jesus transformou a Páscoa judaica (que olhava ao Êxodo do Egito) na Ceia cristã (que olha ao Êxodo do pecado) — o antigo tipo substituído pelo cumprimento definitivo."),
QuizQuestion(id:329,question:"O que é a 'parusia'?",options:["A ascensão de Cristo","O termo grego para a segunda vinda/retorno de Cristo em glória","O Pentecostes","A ressurreição de Cristo"],correctIndex:1,explanation:"Parusia (grego = presença/chegada) é o termo técnico para a segunda vinda de Cristo em glória, usado frequentemente nas epístolas de Paulo.",reference:"1 Tessalonicenses 4:15; Mateus 24:27",category:.geral,propheticMeaning:"A parusia encerra a história da redenção — Cristo que veio como servo humilde voltará como Rei glorioso, cumprindo todas as profecias do Messias reinante que não se cumpriram na primeira vinda."),
QuizQuestion(id:330,question:"Qual é a promessa de 2 Crônicas 7:14?",options:["'O Senhor lutará por vós'","'Se o meu povo, que se chama pelo meu nome, se humilhar, orar, buscar a minha face e se converter, eu os ouvirei e sararei a sua terra'","'Confiai no Senhor para sempre'","'O Senhor abençoará a obra das tuas mãos'"],correctIndex:1,explanation:"2 Crônicas 7:14: 'Se o meu povo se humilhar, orar, buscar a minha face e se converter dos seus maus caminhos, então ouvirei dos céus, perdoarei os seus pecados e sararei a sua terra.'",reference:"2 Crônicas 7:14",category:.geral,propheticMeaning:"A condição — humilhação, oração, busca, conversão — revela o coração da nova aliança: não ritual exterior mas transformação interior, antecipando Jeremias 31 e o derramamento do Espírito."),
]
